function calculateTax() {
            const profit = parseFloat(document.getElementById('totalProfit').value);
            if (isNaN(profit)) {
                alert('수익 금액을 입력해주세요.');
                return;
            }

            const deduction = 2500000;
            const taxable = Math.max(0, profit - deduction);
            const tax = taxable * 0.22;

            document.getElementById('taxableIncome').textContent = taxable.toLocaleString();
            document.getElementById('finalTax').textContent = Math.round(tax).toLocaleString();
            document.getElementById('taxResultBox').style.display = 'block';
        }

