.single-summary-card-container {
            font-family: 'Noto Sans KR', sans-serif;
            display: flex;
            justify-content: center;
            align-items: center;
            padding: 20px 10px;
            background-color: #f0f2f5;
            margin: 20px 0;
        }
        .single-summary-card {
            width: 100%;
            max-width: 700px;
            background-color: #ffffff;
            border-radius: 12px;
            box-shadow: 0 6px 18px rgba(0,0,0,0.12);
            padding: 25px;
            display: flex;
            flex-direction: column;
            border: 1px solid #e0e0e0;
            box-sizing: border-box;
        }
        .single-summary-card .card-header {
            display: flex;
            align-items: center;
            border-bottom: 2px solid #1a73e8;
            padding-bottom: 12px;
            margin-bottom: 12px;
        }
        .single-summary-card .card-header-icon {
            font-size: 34px;
            color: #1a73e8;
            margin-right: 14px;
        }
        .single-summary-card .card-header h3 {
            font-size: 26px;
            color: #1a73e8;
            margin: 0;
            line-height: 1.3;
            font-weight: 700;
        }
        .single-summary-card .card-content {
            font-size: 17px;
            line-height: 1.65;
            color: #333;
        }
        .single-summary-card .card-content .highlight {
            background-color: #fffde7;
            padding: 2px 6px;
            border-radius: 3px;
            font-weight: bold;
        }
        .single-summary-card .card-footer {
            font-size: 14px;
            color: #777;
            text-align: center;
            padding-top: 12px;
            border-top: 1px dashed #ddd;
            margin-top: 15px;
        }
